這章處理「狀態可以走到哪些下一步」的題型。面試時先不要急著套 BFS 或 Dijkstra，先回答三件事：狀態是什麼、邊的代價是否相同、visited 是否需要記錄額外維度。

**判斷流程**：
- 所有邊代價相同：用 BFS。
- 邊代價只有 0/1：用 0-1 BFS。
- 邊代價為非負整數：用 Dijkstra。
- 問連通性或逐步合併：考慮並查集。
- 網格題的狀態不一定只有 $(r, c)$，可能還要包含剩餘消除次數、鑰匙集合、方向或目前時間。

**C++：網格 BFS（狀態含額外資源）**

```cpp
int shortestPath(vector<vector<int>>& grid, int k) {
    int m = grid.size(), n = grid[0].size();
    vector<vector<int>> best(m, vector<int>(n, -1));
    queue<array<int, 4>> q; // r, c, remaining_k, dist
    q.push({0, 0, k, 0});
    best[0][0] = k;

    int dirs[5] = {1, 0, -1, 0, 1};
    while (!q.empty()) {
        auto [r, c, left, dist] = q.front();
        q.pop();
        if (r == m - 1 && c == n - 1) return dist;

        for (int d = 0; d < 4; ++d) {
            int nr = r + dirs[d], nc = c + dirs[d + 1];
            if (nr < 0 || nr >= m || nc < 0 || nc >= n) continue;
            int nextLeft = left - grid[nr][nc];
            if (nextLeft < 0) continue;
            if (best[nr][nc] >= nextLeft) continue;
            best[nr][nc] = nextLeft;
            q.push({nr, nc, nextLeft, dist + 1});
        }
    }
    return -1;
}
```

**C++：Dijkstra（非負權最短路）**

```cpp
vector<long long> dijkstra(int n, vector<vector<pair<int, int>>>& g, int src) {
    const long long INF = 4e18;
    vector<long long> dist(n, INF);
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    dist[src] = 0;
    pq.push({0, src});

    while (!pq.empty()) {
        auto [du, u] = pq.top();
        pq.pop();
        if (du != dist[u]) continue;

        for (auto [v, w] : g[u]) {
            if (dist[v] > du + w) {
                dist[v] = du + w;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}
```

複雜度：BFS 通常是 $O(狀態數 + 轉移數)$，Dijkstra 是 $O((V+E)\log V)$。

這章訓練把題目文字轉成圖、樹或 DAG。Google 題常把「人、會議、課程、城市、父子關係」包成關係資料；正確建模後，解法通常會變成 DFS、拓撲排序、樹形 DP、Tarjan 或換根。

**建模檢查表**：
- 關係是否有方向？如果有方向，是否可能有環？
- 如果是樹，根是固定的還是任選的？答案是否會因換根改變？
- 子樹答案能否由孩子合併？是否需要把父側資訊再傳回孩子？
- 圖中是否要找橋、割點或強連通分量？

**C++：拓撲排序 + DAG 最長時間**

```cpp
int minimumTime(int n, vector<vector<int>>& relations, vector<int>& time) {
    vector<vector<int>> g(n);
    vector<int> indeg(n), finish(n);
    for (auto& e : relations) {
        int u = e[0] - 1, v = e[1] - 1;
        g[u].push_back(v);
        indeg[v]++;
    }

    queue<int> q;
    for (int i = 0; i < n; ++i) {
        finish[i] = time[i];
        if (indeg[i] == 0) q.push(i);
    }

    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v : g[u]) {
            finish[v] = max(finish[v], finish[u] + time[v]);
            if (--indeg[v] == 0) q.push(v);
        }
    }
    return *max_element(finish.begin(), finish.end());
}
```

**C++：樹形 DFS，回傳子樹資訊**

```cpp
long long answer = 0;

long long dfs(int u, int parent, vector<vector<int>>& tree, vector<int>& value) {
    long long subtotal = value[u];
    for (int v : tree[u]) {
        if (v == parent) continue;
        subtotal += dfs(v, u, tree, value);
    }

    // 在這裡根據 subtotal 更新答案，例如切出可行連通塊。
    if (subtotal % 3 == 0) {
        answer++;
        return 0;
    }
    return subtotal;
}
```

**C++：Tarjan 找橋**

```cpp
vector<vector<int>> bridges;
vector<int> dfn, low;
int timer = 0;

void tarjan(int u, int parentEdge, vector<vector<pair<int, int>>>& g) {
    dfn[u] = low[u] = ++timer;
    for (auto [v, eid] : g[u]) {
        if (eid == parentEdge) continue;
        if (!dfn[v]) {
            tarjan(v, eid, g);
            low[u] = min(low[u], low[v]);
            if (low[v] > dfn[u]) bridges.push_back({u, v});
        } else {
            low[u] = min(low[u], dfn[v]);
        }
    }
}
```

這章的核心是把暴力搜尋改成「只記必要資訊」。先定義狀態，再判斷狀態之間如何轉移；如果狀態數太大，再找排序、前綴和、二分、單調性或狀態壓縮。

**DP 設計步驟**：
1. 定義狀態：目前處理到哪裡？還剩什麼限制？答案需要最大、最小還是計數？
2. 找最後一步：最後選了什麼、接在哪個狀態後面？
3. 寫初始值與非法值：最小化常用 INF，最大化常用負無限。
4. 壓縮空間前，先確認轉移只依賴上一層或固定方向。

**C++：帶權區間排程 DP**

```cpp
int jobScheduling(vector<int>& start, vector<int>& end, vector<int>& profit) {
    int n = start.size();
    vector<array<int, 3>> jobs;
    for (int i = 0; i < n; ++i) jobs.push_back({end[i], start[i], profit[i]});
    sort(jobs.begin(), jobs.end());

    vector<int> ends(n), dp(n + 1);
    for (int i = 0; i < n; ++i) ends[i] = jobs[i][0];

    for (int i = 1; i <= n; ++i) {
        auto [e, s, p] = jobs[i - 1];
        int j = upper_bound(ends.begin(), ends.end(), s) - ends.begin();
        dp[i] = max(dp[i - 1], dp[j] + p);
    }
    return dp[n];
}
```

**C++：狀壓 DP（集合覆蓋）**

```cpp
vector<int> smallestSufficientTeam(vector<string>& req, vector<vector<string>>& people) {
    int m = req.size();
    unordered_map<string, int> id;
    for (int i = 0; i < m; ++i) id[req[i]] = i;

    int full = 1 << m;
    vector<vector<int>> dp(full);
    vector<char> seen(full);
    seen[0] = true;

    for (int i = 0; i < (int)people.size(); ++i) {
        int mask = 0;
        for (auto& skill : people[i]) mask |= 1 << id[skill];
        auto old = dp;
        auto oldSeen = seen;
        for (int s = 0; s < full; ++s) {
            if (!oldSeen[s]) continue;
            int ns = s | mask;
            if (!seen[ns] || old[s].size() + 1 < dp[ns].size()) {
                dp[ns] = old[s];
                dp[ns].push_back(i);
                seen[ns] = true;
            }
        }
    }
    return dp[full - 1];
}
```

複雜度通常由「狀態數 × 每個狀態的轉移數」決定。面試中要能明確說出狀態是否覆蓋所有可能，以及為什麼不重不漏。

字串題的第一步是判斷「比較單位」。如果比較前綴/後綴，可用 KMP 或 Z 函式；如果比較大量子串，可用 rolling hash；如果要反覆走字典中的字首，可用 Trie；如果是字串轉換，通常要建圖後跑最短路或 DP。

**常見選型**：
- 找 pattern 在 text 中出現：KMP / Z。
- 快速比較兩段子串是否相等：rolling hash。
- 多個字典詞匹配 target 的前綴：Trie + DP/BFS。
- 字元或字串替換有代價：建圖後最短路，再做 DP。

**C++：KMP 前綴函式**

```cpp
vector<int> prefixFunction(const string& s) {
    int n = s.size();
    vector<int> pi(n);
    for (int i = 1; i < n; ++i) {
        int j = pi[i - 1];
        while (j > 0 && s[i] != s[j]) j = pi[j - 1];
        if (s[i] == s[j]) j++;
        pi[i] = j;
    }
    return pi;
}

vector<int> findMatches(const string& text, const string& pat) {
    string s = pat + '#' + text;
    vector<int> pi = prefixFunction(s), ans;
    int m = pat.size();
    for (int i = m + 1; i < (int)s.size(); ++i) {
        if (pi[i] == m) ans.push_back(i - 2 * m);
    }
    return ans;
}
```

**C++：Trie + DP 最少拼接數**

```cpp
struct TrieNode {
    int next[26];
    bool end = false;
    TrieNode() { memset(next, -1, sizeof(next)); }
};

int minWords(vector<string>& words, string target) {
    vector<TrieNode> trie(1);
    for (auto& w : words) {
        int u = 0;
        for (char ch : w) {
            int c = ch - 'a';
            if (trie[u].next[c] == -1) {
                trie[u].next[c] = trie.size();
                trie.emplace_back();
            }
            u = trie[u].next[c];
        }
        trie[u].end = true;
    }

    const int INF = 1e9;
    int n = target.size();
    vector<int> dp(n + 1, INF);
    dp[0] = 0;
    for (int i = 0; i < n; ++i) {
        if (dp[i] == INF) continue;
        int u = 0;
        for (int j = i; j < n; ++j) {
            int c = target[j] - 'a';
            if (trie[u].next[c] == -1) break;
            u = trie[u].next[c];
            if (trie[u].end) dp[j + 1] = min(dp[j + 1], dp[i] + 1);
        }
    }
    return dp[n] == INF ? -1 : dp[n];
}
```

資料結構題的關鍵不是認出容器名稱，而是維護不變式。每次操作後，資料結構必須仍能快速回答題目需要的最大值、最小值、歷史值、區間交集或第 k 個元素。

**選型提示**：
- 需要動態最大/最小：heap，若有刪除舊值，使用懶刪除。
- 需要有序前驅/後繼：set / map。
- 需要歷史版本查詢：每個位置存時間序列，再二分。
- 查詢可離線排序：把資料和 query 依門檻排序，逐步加入候選集合。

**C++：懶刪除最大堆**

```cpp
priority_queue<pair<long long, int>> pq; // value, id
unordered_map<int, long long> current;

void update(int id, long long value) {
    current[id] = value;
    pq.push({value, id});
}

long long getMax() {
    while (!pq.empty()) {
        auto [value, id] = pq.top();
        if (current.count(id) && current[id] == value) return value;
        pq.pop();
    }
    return 0;
}
```

**C++：Snapshot Array 核心做法**

```cpp
class SnapshotArray {
    int snapId = 0;
    vector<vector<pair<int, int>>> history;

public:
    SnapshotArray(int length) : history(length, {{0, 0}}) {}

    void set(int index, int val) {
        if (history[index].back().first == snapId) {
            history[index].back().second = val;
        } else {
            history[index].push_back({snapId, val});
        }
    }

    int snap() { return snapId++; }

    int get(int index, int id) {
        auto& h = history[index];
        int pos = upper_bound(h.begin(), h.end(), pair<int, int>{id, INT_MAX}) - h.begin() - 1;
        return h[pos].second;
    }
};
```

離線題常見複雜度是排序 $O((n+q)\log(n+q))$ 加上資料結構操作；設計前先確認 query 可否重排，答案是否只依賴門檻而不依賴原順序。

這章處理「答案不是直接算，而是要找邊界或維護一段窗口」的題型。二分答案需要單調性，貪心需要可證明的局部選擇，滑動視窗需要能在左右指標移動時維護合法性。

**快速判斷**：
- 問最大化最小值、最小化最大值、最多能撐多久：考慮二分答案。
- 排序後做選擇，局部選擇能用交換論證證明：考慮貪心。
- 子陣列/子字串條件隨右端點擴張、左端點收縮：考慮滑動視窗。

**C++：二分答案模板**

```cpp
bool feasible(long long x, vector<int>& nums) {
    // 回傳答案至少/至多為 x 時是否可行。
    // 必須滿足單調性：若 x 可行，某一側全部可行。
    return true;
}

long long binaryAnswer(vector<int>& nums) {
    long long lo = 0, hi = 1e18;
    while (lo < hi) {
        long long mid = lo + (hi - lo) / 2;
        if (feasible(mid, nums)) {
            hi = mid;
        } else {
            lo = mid + 1;
        }
    }
    return lo;
}
```

**C++：滑動視窗（至多 k 個壞元素）**

```cpp
int longestWindow(vector<int>& nums, int k) {
    int left = 0, bad = 0, ans = 0;
    for (int right = 0; right < (int)nums.size(); ++right) {
        if (nums[right] == 0) bad++;
        while (bad > k) {
            if (nums[left] == 0) bad--;
            left++;
        }
        ans = max(ans, right - left + 1);
    }
    return ans;
}
```

**C++：交換論證型排序骨架**

```cpp
struct Job {
    long long cost;
    long long weight;
};

sort(jobs.begin(), jobs.end(), [](const Job& a, const Job& b) {
    // 比較 a 在前與 b 在前的總代價。
    return a.cost * b.weight < b.cost * a.weight;
});
```

面試中要主動說明單調性或交換論證；只說「看起來可以二分/貪心」通常不夠。

這一章補強資料平行、記憶體存取、同步點與吞吐量。刷題時可以刻意把問題改寫成「每個元素/節點/邊是否能獨立處理」、「哪些步驟需要 prefix scan 或 reduction」、「資料是否連續讀寫」。

**複習重點**：
- 平行 map：每個元素獨立轉換，適合 SIMD/SIMT。
- reduction：把多個值合併成一個值，例如最大值、總和、OR/XOR。
- prefix scan：每個位置需要前面累積資訊，常用於壓縮、分段、計數與位移。
- memory coalescing：連續執行緒讀連續記憶體比隨機讀更容易拿到高吞吐。

**C++：CPU 版 inclusive scan，對應 GPU scan 概念**

```cpp
vector<long long> inclusiveScan(const vector<int>& a) {
    vector<long long> scan(a.size());
    long long acc = 0;
    for (int i = 0; i < (int)a.size(); ++i) {
        acc += a[i];
        scan[i] = acc;
    }
    return scan;
}
```

**C++：分塊 reduction，模擬 block-local reduction**

```cpp
long long blockReduceSum(const vector<int>& a, int blockSize) {
    vector<long long> partial;
    for (int l = 0; l < (int)a.size(); l += blockSize) {
        long long sum = 0;
        for (int i = l; i < min((int)a.size(), l + blockSize); ++i) {
            sum += a[i];
        }
        partial.push_back(sum);
    }
    return accumulate(partial.begin(), partial.end(), 0LL);
}
```

**面試表達**：你可以說明哪些 loop-carried dependency 阻止平行化，哪些資料可以先做 prefix/reduction，再進入下一階段。

這一章更在意資源邊界：記憶體是否固定、是否能避免配置碎片、整數是否溢位、狀態是否能用 bit mask 表示、操作是否有最壞情況延遲。即使題目是一般資料結構，也要主動說出空間上限與失敗路徑。

**複習重點**：
- 固定容量：避免無限制成長，明確處理 full/empty。
- 位元狀態：用 mask 表示多個布林值，操作通常是 $O(1)$。
- 記憶體配置：連續區間、free list、first-fit/best-fit 都要能說明 tradeoff。
- 邊界條件：溢位、負數、wrap-around index、重複釋放。

**C++：固定容量 ring buffer**

```cpp
class RingBuffer {
    vector<int> buf;
    int head = 0, tail = 0, count = 0;

public:
    RingBuffer(int capacity) : buf(capacity) {}

    bool push(int x) {
        if (count == (int)buf.size()) return false;
        buf[tail] = x;
        tail = (tail + 1) % buf.size();
        count++;
        return true;
    }

    bool pop(int& out) {
        if (count == 0) return false;
        out = buf[head];
        head = (head + 1) % buf.size();
        count--;
        return true;
    }
};
```

**C++：bit mask 狀態操作**

```cpp
bool hasFlag(uint32_t mask, int bit) {
    return (mask & (1u << bit)) != 0;
}

uint32_t setFlag(uint32_t mask, int bit) {
    return mask | (1u << bit);
}

uint32_t clearFlag(uint32_t mask, int bit) {
    return mask & ~(1u << bit);
}
```

這一章常以 API 設計形式出現：每個 API 的複雜度、資料一致性與索引同步都要清楚。常見做法是用多個資料結構維護同一批實體，例如 map 找 id、set 排名、heap 取最值，更新時同步所有索引。

**複習重點**：
- 先列 API，再為每個 API 寫目標複雜度。
- 定義 canonical state：哪份資料是事實來源。
- 衍生索引要能刪舊插新，避免 stale entry。
- 排名規則要固定 tie-breaker，否則 set/map 結果不穩。

**C++：雙索引排名資料結構**

```cpp
struct Item {
    int score;
    string name;
};

struct RankCmp {
    bool operator()(const Item& a, const Item& b) const {
        if (a.score != b.score) return a.score > b.score;
        return a.name < b.name;
    }
};

class Ranking {
    unordered_map<string, int> scoreByName;
    set<Item, RankCmp> ranking;

public:
    void update(const string& name, int score) {
        if (scoreByName.count(name)) {
            ranking.erase({scoreByName[name], name});
        }
        scoreByName[name] = score;
        ranking.insert({score, name});
    }

    string top() const {
        return ranking.begin()->name;
    }
};
```

**C++：時間桶統計**

```cpp
class TimeCounter {
    map<int, int> events;

public:
    void record(int timestamp) {
        events[timestamp]++;
    }

    int query(int start, int end) {
        int ans = 0;
        for (auto it = events.lower_bound(start); it != events.end() && it->first <= end; ++it) {
            ans += it->second;
        }
        return ans;
    }
};
```

如果查詢量很大，再把時間切成固定 bucket 或 Fenwick tree；說清楚更新與查詢的成本。

這類題不是在原圖上搜尋，而是在「狀態圖」上搜尋。狀態需要包含所有會影響未來合法轉移的資訊，例如目前節點、已拿到的鑰匙集合、箱子位置、玩家位置、已訪問節點集合等。只要兩個路徑抵達同一個完整狀態，後續可行操作完全相同，就可以用 visited 去重。

**使用時機**：
- 題目有「收集所有」、「訪問所有」、「移動箱子」、「操作後狀態改變」等描述。
- 單純的位置不足以判斷下一步，例如同一格在不同 keys mask 下可走的門不同。
- 初始狀態可能不只一個，例如可從任意節點開始訪問所有節點。

**實作重點**：
- 先寫狀態 tuple，再寫 encode 函式或多維陣列索引。
- visited 要記完整狀態，不能只記位置。
- 邊權全 1 用 BFS；邊權 0/1 用 deque；一般非負權用 Dijkstra。
- 狀態數通常是 $O(n \cdot 2^n)$ 或 $O(mn \cdot 2^k)$，要先估算是否可行。

**C++：多源 bitmask BFS**

```cpp
int shortestPathVisitingAllNodes(vector<vector<int>>& graph) {
    int n = graph.size();
    int full = (1 << n) - 1;
    queue<pair<int, int>> q; // node, visited_mask
    vector<vector<int>> dist(n, vector<int>(1 << n, -1));

    for (int i = 0; i < n; ++i) {
        int mask = 1 << i;
        dist[i][mask] = 0;
        q.push({i, mask});
    }

    while (!q.empty()) {
        auto [u, mask] = q.front();
        q.pop();
        if (mask == full) return dist[u][mask];

        for (int v : graph[u]) {
            int nextMask = mask | (1 << v);
            if (dist[v][nextMask] != -1) continue;
            dist[v][nextMask] = dist[u][mask] + 1;
            q.push({v, nextMask});
        }
    }
    return -1;
}
```

**常見錯誤**：把 $(node, mask)$ 簡化成 node，會把「同一位置但資源不同」的狀態錯誤合併。

多階段最短路題通常不是一次 Dijkstra 就結束，而是要把路徑條件拆成幾份可重用的距離表。這類題常見於「兩個起點最後匯合」、「找第二短路」、「有時間等待規則」、「特殊道路可選」等情境。

**使用時機**：
- 題目問 src1 到某點、src2 到某點，再一起走到 dest 的匯合路徑。
- 題目要求第二短、受限時間內最短、或到達時間會被交通燈/週期影響。
- 圖的邊權非負，可以穩定使用 Dijkstra。

**實作重點**：
- 匯合型：從 src1、src2 跑正圖距離，從 dest 跑反圖距離，枚舉中繼點。
- 第二短：每個節點保留兩個不同距離，鬆弛時避免把相同距離重複算入。
- 時間規則：把「等待到下一個可出發時間」寫在 relax 前，讓 dist 仍代表實際抵達時間。
- 複雜度通常是幾次 $O((V+E)\log V)$。

**C++：每個點保留最短與次短距離**

```cpp
vector<array<long long, 2>> secondShortest(int n, vector<vector<pair<int, int>>>& g, int src) {
    const long long INF = 4e18;
    vector<array<long long, 2>> dist(n, {INF, INF});
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<>> pq;
    dist[src][0] = 0;
    pq.push({0, src});

    while (!pq.empty()) {
        auto [du, u] = pq.top();
        pq.pop();
        if (du > dist[u][1]) continue;

        for (auto [v, w] : g[u]) {
            long long nd = du + w;
            if (nd < dist[v][0]) {
                swap(nd, dist[v][0]);
                pq.push({dist[v][0], v});
            }
            if (dist[v][0] < nd && nd < dist[v][1]) {
                dist[v][1] = nd;
                pq.push({nd, v});
            }
        }
    }
    return dist;
}
```

**常見錯誤**：第二短路要保留「嚴格不同」的距離；如果允許相同距離重複入隊，答案可能變成另一條同長最短路。

高階樹題的核心是把「子樹」變成可計算的範圍，或把「換根後答案」用父節點答案推導出來。這類題常見於刪除子樹、切兩條邊、統計所有根的答案、或要求每個節點作為根時的最優值。

**使用時機**：
- 題目問刪掉某個子樹後剩下的高度、和、XOR、直徑等。
- 題目需要對每個節點都求一次以它為根的答案。
- 枚舉切邊或切點時，需要快速判斷一個節點是否在另一個節點子樹內。

**實作重點**：
- Euler tour：用 tin/tout 把子樹轉為連續區間。
- 後序 DFS：彙總子樹 size/sum/xor/depth。
- 前序下傳或換根：把父側貢獻傳給孩子。
- 切兩條邊時，先用祖先關係區分「嵌套子樹」和「互不相交子樹」。

**C++：Euler tour 判斷祖先關係**

```cpp
vector<int> tin, tout;
int timer = 0;

void dfsOrder(int u, int parent, vector<vector<int>>& tree) {
    tin[u] = ++timer;
    for (int v : tree[u]) {
        if (v != parent) dfsOrder(v, u, tree);
    }
    tout[u] = timer;
}

bool isAncestor(int u, int v) {
    return tin[u] <= tin[v] && tin[v] <= tout[u];
}
```

**C++：換根 DP 距離和骨架**

```cpp
void dfs1(int u, int p, vector<vector<int>>& g, vector<int>& size, vector<long long>& ans) {
    size[u] = 1;
    for (int v : g[u]) {
        if (v == p) continue;
        dfs1(v, u, g, size, ans);
        size[u] += size[v];
        ans[u] += ans[v] + size[v];
    }
}

void dfs2(int u, int p, vector<vector<int>>& g, vector<int>& size, vector<long long>& ans, int n) {
    for (int v : g[u]) {
        if (v == p) continue;
        ans[v] = ans[u] - size[v] + (n - size[v]);
        dfs2(v, u, g, size, ans, n);
    }
}
```

字串高階題通常是「字串演算法 + 另一層 DP/計數/資料結構」。KMP、Z 函式、Trie、rolling hash 只是取得比較資訊的工具，真正的答案常要再透過 DP 或資料結構累積。

**使用時機**：
- 需要大量比較前綴、後綴或 LCP，不能每次逐字比較。
- 題目要求前後綴對、幾乎相等子串、字典詞拼接、刪除操作最大次數。
- 字串長度大，$O(n^2)$ 字元比較不可行，但 $O(n^2)$ 狀態搭配 $O(1)$ LCP 查詢可能可行。

**實作重點**：
- Z 函式適合比較 s[i...] 和整個字串前綴。
- KMP prefix function 適合 border 和模式匹配。
- rolling hash 適合任意兩段子串比較，但要注意碰撞。
- Trie 適合多個字典詞前綴匹配，常接 DP。

**C++：Z 函式**

```cpp
vector<int> zFunction(const string& s) {
    int n = s.size();
    vector<int> z(n);
    for (int i = 1, l = 0, r = 0; i < n; ++i) {
        if (i <= r) z[i] = min(r - i + 1, z[i - l]);
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) z[i]++;
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}
```

**C++：用 LCP 判斷一次 mismatch**

```cpp
bool almostEqual(int lcpLeft, int lcpRight, int len) {
    // 允許至多一個位置不同：左側匹配長度 + 右側匹配長度 >= len - 1
    return lcpLeft + lcpRight >= len - 1;
}
```

高階 DP 的訊號是狀態容易寫，但轉移太慢。先保留清楚的 $O(n^2)$ 或 $O(nk)$ 定義，再觀察轉移是否只需要某個前綴最小值、最大值、單調隊列或排序後的最近合法狀態。

**使用時機**：
- 樸素轉移需要枚舉前一個決策點 $j$，導致 $O(n^2)$ 或更高。
- 決策點有相容條件，例如前一個活動必須在目前活動開始前結束。
- 轉移形式有前綴最小值、最大值、滑動窗口最值或可二分的邊界。

**Pattern**：
- 區間/排程：排序 + 二分前一個相容狀態。
- $dp[i] = \min(dp[j] + cost(j, i))$：檢查單調隊列或斜率優化條件。
- 有跳過次數/資源數：資源維度通常是第二維。
- 轉移帶最大值/最小值：維護前綴最佳候選。

**C++：排序 + 二分相容狀態**

```cpp
int maxValue(vector<vector<int>>& events, int k) {
    sort(events.begin(), events.end(), [](auto& a, auto& b) {
        return a[1] < b[1];
    });
    int n = events.size();
    vector<int> ends(n);
    for (int i = 0; i < n; ++i) ends[i] = events[i][1];

    vector<vector<int>> dp(n + 1, vector<int>(k + 1));
    for (int i = 1; i <= n; ++i) {
        int start = events[i - 1][0];
        int value = events[i - 1][2];
        int prev = lower_bound(ends.begin(), ends.end(), start) - ends.begin();
        for (int used = 1; used <= k; ++used) {
            dp[i][used] = max(dp[i - 1][used], dp[prev][used - 1] + value);
        }
    }
    return dp[n][k];
}
```

**常見錯誤**：急著優化前沒有先寫清楚狀態定義，會導致二分的相容位置或資源維度 off-by-one。
